(function(){angular.module('prismaAppCreateBundle',[]).controller('prismaCreateBundleController',['$scope','requestParam','PrismaSettingsService','PRISMA_CONSTANT','$modalInstance',function($scope,requestParam,PrismaSettingsService,PRISMA_CONSTANT,$modalInstance){let createBundlesVar=this;createBundlesVar.msg1="keyword1";createBundlesVar.msg2="keyword2";let alphabetPattern=/^[a-zA-Z \s]+$/;let firstTwoCharPattern=/^[a-zA-Z0-9]+$/;let keywordCharPattern=/^.*[a-zA-Z0-9]+.*$/;let ALPHANUMERIC_MSG="Please enter at least 2 alphanumeric characters.";let ALPHABETIC_MSG="Please enter at least 2 alphabetic characters.";createBundlesVar.placeholder="Create";createBundlesVar.patientId=requestParam.patientId;createBundlesVar.userfullname=requestParam.userFullName;createBundlesVar.keywordConfiguration=[];createBundlesVar.keywordConfiguration=[{bundleKeywordName:'',bundleKeywordColor:'#11A683'},{bundleKeywordName:'',bundleKeywordColor:'#11A683'},{bundleKeywordName:'',bundleKeywordColor:'#11A683'},{bundleKeywordName:'',bundleKeywordColor:'#11A683'},{bundleKeywordName:'',bundleKeywordColor:'#11A683'}];createBundlesVar.newBundleName="";if(requestParam.bundleItem){createBundlesVar.bundleItem=requestParam.bundleItem;createBundlesVar.newBundleName=createBundlesVar.bundleItem.bundleName;for(let index=0;index<createBundlesVar.bundleItem.bundleKeywords.length;index++){createBundlesVar.keywordConfiguration[index].bundleKeywordName=createBundlesVar.bundleItem.bundleKeywords[index].bundleKeywordName}createBundlesVar.placeholder="Save"}createBundlesVar.bundleNameErrorMsg="";createBundlesVar.bundleOnkeyup=function(){let msg="";msg=bundleNameValidation();$("#prismaBundleNameErrorMsg").html(msg)};function bundleNameValidation(){var msg="";let bundleName=angular.element("#prisma-create-bundle-name")!==undefined?$.trim(angular.element("#prisma-create-bundle-name").val()):undefined;let re=new RegExp(alphabetPattern);if(bundleName===undefined){msg=""}else if(bundleName===""){msg="Please enter Bundle Name."}else if(bundleName.length>30){msg="Please enter less than 30 characters."}else if(bundleName.length<2){msg=ALPHABETIC_MSG}else if(re.test(createBundlesVar.newBundleName)===false){msg="Bundle Name must be alphabetic characters only."}return msg}createBundlesVar.keywordOnkeyup=function(index){let msg="";let keyword=$.trim($("#bundleKeywordName"+index).val());msg=keywordValidation(keyword);$("#msg"+index).html(msg)};function keywordValidation(keyword){var msg="";let re;if(keyword==null||keyword===undefined||keyword===""){msg=""}else if(keyword.length>25){msg="Please enter less than 25 characters."}else if(keyword.length<2){msg=ALPHANUMERIC_MSG}else if(keyword.length===PRISMA_CONSTANT.SEARCH_STRING.MIN_LENGTH){re=new RegExp(firstTwoCharPattern);if(re.test(keyword)===false){msg="The first 2 characters of keyword must be alphanumeric."}}else{re=new RegExp(keywordCharPattern);if(re.test(keyword)===false){msg="Please enter at least one alpha-numeric character."}}return msg}createBundlesVar.dismissModal=function(actionEvent){$modalInstance.dismiss(actionEvent)};createBundlesVar.isBundleSubmitted=false;createBundlesVar.createBundle=function(){createBundlesVar.isBundleSubmitted=true;let keywordArray=[];let keywordNameArray=[];var msg=bundleNameValidation();if(msg&&msg!==""){ecwAlert(msg);return}for(let item of createBundlesVar.keywordConfiguration){if(item.bundleKeywordName!==null&&item.bundleKeywordName.trim()!==''){for(let index=0;index<keywordNameArray.length;index++){if(angular.lowercase(item.bundleKeywordName)===angular.lowercase(keywordNameArray[index])){ecwAlert("Duplicate keywords are not allowed.");return}}msg=keywordValidation(item.bundleKeywordName);if(msg&&msg!==""){ecwAlert(msg);return}keywordArray.push(item);keywordNameArray.push(item.bundleKeywordName)}}let newBundle={bundleName:createBundlesVar.newBundleName.trim(),bundleKeywords:keywordArray,bundleId:null};if(keywordArray.length<=0){ecwAlert("Please enter at least one keyword.");return}let bundleObj=[];newBundle.bundleId=createBundlesVar.bundleItem===undefined?null:createBundlesVar.bundleItem.id;bundleObj.push(newBundle);PrismaSettingsService.createPrismaUserBundle(JSON.stringify(bundleObj)).then(response=>{createBundlesVar.isBundleSubmitted=false;if(response){if(response.status&&"failed"===response.status){ecwAlert(response.message&&response.message!==""?response.message:"Something went wrong, please try again later.");return}$modalInstance.close("success")}},function(){createBundlesVar.isBundleSubmitted=false;ecwAlert("Something went wrong, please try again later.")})};createBundlesVar.clearKeywords=function(){let index=1;for(let item of createBundlesVar.keywordConfiguration){item.bundleKeywordName='';$("#bundleKeywordName"+index).removeClass("x");$(".prisma-create-bundle-settings #msg"+index).html("");index++}}}])})();